import redis

# Connect to Redis server
redis_client = redis.Redis(host='localhost', port=6379, db=0)

# Get Lua script code from user input
lua_script = input("Enter Lua script code: ")

# Get user parameters from input
user_params = input("Enter user parameters separated by commas: ").split(',')

# Execute Lua script using redis.eval()
result = redis_client.eval(lua_script, user_params)

# Print the result
print("Result:", result)